import{c as n,S as i,j as h,m as t}from"./chunks/framework.8aa1YH_s.js";const p=JSON.parse('{"title":"Khóa học của tôi","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/khoa-hoc-cua-toi.md","filePath":"hoc-vien/khoa-hoc-cua-toi.md","lastUpdated":0}'),o={name:"hoc-vien/khoa-hoc-cua-toi.md"};function r(g,a,s,c,l,e){return i(),h("div",null,[...a[0]||(a[0]=[t(`<h1 id="khoa-hoc-cua-toi" tabindex="-1">Khóa học của tôi <a class="header-anchor" href="#khoa-hoc-cua-toi" aria-label="Permalink to “Khóa học của tôi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/khoa-hoc</code></p><p>Nơi tập hợp tất cả khóa học bạn <strong>đã mua</strong> hoặc <strong>được gán</strong>.</p><h2 id="giao-dien-trang" tabindex="-1">Giao diện trang <a class="header-anchor" href="#giao-dien-trang" aria-label="Permalink to “Giao diện trang”">​</a></h2><p>Mỗi khóa hiển thị dưới dạng thẻ:</p><ul><li>Ảnh bìa</li><li>Tên khóa, giáo viên</li><li><strong>Tiến độ học</strong> (%)</li><li><strong>Ngày hết hạn</strong></li><li>Nút <strong>Học ngay</strong></li></ul><h2 id="trang-thai-khoa" tabindex="-1">Trạng thái khóa <a class="header-anchor" href="#trang-thai-khoa" aria-label="Permalink to “Trạng thái khóa”">​</a></h2><table tabindex="0"><thead><tr><th>Nhãn</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td><strong>Đang học</strong></td><td>Bạn có thể vào học bình thường</td></tr><tr><td><strong>Chưa bắt đầu</strong></td><td>Khóa chưa tới ngày bắt đầu</td></tr><tr><td><strong>Sắp hết hạn</strong></td><td>Còn dưới 30 ngày</td></tr><tr><td><strong>Đã hết hạn</strong></td><td>Không vào học được nữa (cần gia hạn)</td></tr><tr><td><strong>Tạm khóa</strong></td><td>Bị thu hồi quyền học (vd: vi phạm)</td></tr></tbody></table><h2 id="vao-khoa-hoc" tabindex="-1">Vào khóa học <a class="header-anchor" href="#vao-khoa-hoc" aria-label="Permalink to “Vào khóa học”">​</a></h2><ol><li>Bấm <strong>Học ngay</strong> trên thẻ khóa.</li><li>Bạn được đưa vào <strong>trang luyện tập của khóa</strong> (<code>https://lamsonedutech.vn/luyen-tap/luyen-tap/:id</code>).</li><li>Bên trái: cây nội dung <strong>Chương → Chuyên đề</strong>.</li><li>Bên phải: nội dung bài đang xem.</li></ol><h2 id="cay-noi-dung" tabindex="-1">Cây nội dung <a class="header-anchor" href="#cay-noi-dung" aria-label="Permalink to “Cây nội dung”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Khóa học</span></span>
<span class="line"><span>├── 📘 Chương 1: Hàm số</span></span>
<span class="line"><span>│   ├── ✅ Bài 1.1 - Tập xác định (đã học)</span></span>
<span class="line"><span>│   ├── 🎬 Bài 1.2 - Hàm số bậc nhất (đang xem)</span></span>
<span class="line"><span>│   ├── 🔒 Bài 1.3 - Hàm số bậc 2 (chưa mở khóa)</span></span>
<span class="line"><span>│   └── 📝 Kiểm tra cuối chương 1</span></span>
<span class="line"><span>└── 📘 Chương 2: ...</span></span></code></pre></div><ul><li><strong>🎬 Video</strong> = bài giảng video.</li><li><strong>📄 Văn bản</strong> = bài giảng dạng đọc.</li><li><strong>📝 Bài kiểm tra</strong> = đề thi cuối chuyên đề/chương.</li><li><strong>🔒</strong> = chưa mở khóa (cần hoàn thành bài trước).</li><li><strong>✅</strong> = đã hoàn thành.</li></ul><h2 id="hoc-bai-giang" tabindex="-1">Học bài giảng <a class="header-anchor" href="#hoc-bai-giang" aria-label="Permalink to “Học bài giảng”">​</a></h2><p>→ Xem chi tiết tại <a href="./hoc-bai-giang">Học bài giảng</a>.</p><h2 id="lam-bai-kiem-tra" tabindex="-1">Làm bài kiểm tra <a class="header-anchor" href="#lam-bai-kiem-tra" aria-label="Permalink to “Làm bài kiểm tra”">​</a></h2><p>→ Xem chi tiết tại <a href="./luyen-tap">Luyện tập</a>.</p><h2 id="xem-lich-su-trong-khoa" tabindex="-1">Xem lịch sử trong khóa <a class="header-anchor" href="#xem-lich-su-trong-khoa" aria-label="Permalink to “Xem lịch sử trong khóa”">​</a></h2><p>Trong khóa, tab <strong>Lịch sử</strong>:</p><ul><li>Liệt kê các bài thi đã làm.</li><li>Bấm vào để <strong>Xem lại bài thi</strong> (đáp án + lời giải).</li></ul><h2 id="gia-han-khoa" tabindex="-1">Gia hạn khóa <a class="header-anchor" href="#gia-han-khoa" aria-label="Permalink to “Gia hạn khóa”">​</a></h2><p>Khi khóa sắp hết hạn:</p><ol><li>Trên thẻ khóa, bấm <strong>Gia hạn</strong>.</li><li>Chọn gói gia hạn (1 tháng / 3 tháng / 6 tháng).</li><li>Thanh toán như mua khóa mới.</li></ol><blockquote><p>💡 Một số khóa không cho gia hạn online. Khi đó liên hệ trung tâm.</p></blockquote><h2 id="hoi-đap-voi-giao-vien" tabindex="-1">Hỏi đáp với giáo viên <a class="header-anchor" href="#hoi-đap-voi-giao-vien" aria-label="Permalink to “Hỏi đáp với giáo viên”">​</a></h2><p>Bên trong khóa, có nút <strong>Đặt câu hỏi</strong> ở:</p><ul><li>Dưới mỗi bài giảng.</li><li>Sau khi xem đáp án câu hỏi sai.</li><li>Trong khu <strong>Thảo luận của khóa</strong>.</li></ul><p>→ Xem <a href="./hoi-dap">Hỏi đáp với giáo viên</a>.</p><h2 id="đanh-gia-khoa-hoc" tabindex="-1">Đánh giá khóa học <a class="header-anchor" href="#đanh-gia-khoa-hoc" aria-label="Permalink to “Đánh giá khóa học”">​</a></h2><p>Sau khi hoàn thành ≥ 50% nội dung (tùy hệ thống), bạn được mời <strong>đánh giá khóa</strong>:</p><ul><li>Số sao (1-5)</li><li>Nhận xét</li><li>Có thể chia sẻ công khai hoặc gửi riêng giáo viên</li></ul><p>Đánh giá giúp các học viên sau có thông tin chọn khóa, và giúp giáo viên cải thiện.</p><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi đã mua khóa nhưng không thấy trong danh sách?</strong> → Kiểm tra: hóa đơn đã được xác nhận chưa? Có thể chuyển khoản chưa được duyệt. Liên hệ trung tâm gửi biên lai.</p><p><strong>Bài giảng tự nhảy về 0% sau khi tôi đã học?</strong> → Đảm bảo bạn đăng nhập đúng tài khoản. Reload và kiểm tra lại. Nếu vẫn mất, báo Hỏi đáp.</p><p><strong>Tôi muốn học chuyên đề 3 nhưng nó bị khóa?</strong> → Khóa của bạn có thể yêu cầu hoàn thành chuyên đề trước hoặc đạt điểm tối thiểu bài kiểm tra. Quay lại chuyên đề trước, học và làm bài.</p><p><strong>Khóa đã hết hạn, tôi mất tiến độ?</strong> → Tiến độ vẫn lưu trên hệ thống. Khi gia hạn, bạn tiếp tục từ chỗ cũ.</p>`,37)])])}const k=n(o,[["render",r]]);export{p as __pageData,k as default};
